mapper.update:
UPDATE SPRINT
SET
    STATUS = #{status},
    UPDATED_AT = #{updatedAt}
WHERE SPRINT_ID = #{sprintId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}

mapper.select:
SELECT
FROM SPRINT S INNER JOIN PROJECT P ON S.PROJECT_ID = P.PROJECT_ID
AND S.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND S.STATUS = #{status}
AND ( S.SPRINT_NAME ILIKE CONCAT('%', #{keyword}, '%') OR S.GOAL ILIKE CONCAT('%', #{keyword}, '%') OR P.PROJECT_CODE ILIKE CONCAT('%', #{keyword}, '%') OR P.PROJECT_NAME ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY S.START_DATE DESC, S.CREATED_AT DESC

SELECT COALESCE(MAX(DISPLAY_ORDER), 0)
FROM SPRINT_ISSUE
WHERE SPRINT_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}

mapper.update:
UPDATE SPRINT_ISSUE
SET DISPLAY_ORDER = #{displayOrder}
WHERE SPRINT_ID = #{sprintId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
  AND ISSUE_ID = #{issueId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}

mapper.delete:
DELETE FROM SPRINT_ISSUE
WHERE SPRINT_ID = #{sprintId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
  AND ISSUE_ID = #{issueId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
